import{_ as a,H as t,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"Subagents 子代理","description":"","frontmatter":{},"headers":[],"relativePath":"claudeLearning/07-Subagents子代理.md","filePath":"claudeLearning/07-Subagents子代理.md","lastUpdated":1778496697000}'),i={name:"claudeLearning/07-Subagents子代理.md"};function l(p,s,o,r,d,u){return t(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="subagents-子代理" tabindex="-1">Subagents 子代理 <a class="header-anchor" href="#subagents-子代理" aria-label="Permalink to &quot;Subagents 子代理&quot;">​</a></h1><p>主对话和 Claude 聊得久了上下文会爆——读了 50 个文件、跑了 100 条命令,context 窗口快满,LLM 开始忘事、决策质量下降。<strong>Subagent 就是用来解决这个的</strong>:把一段子任务派给独立的 Claude,它在自己的上下文里跑完、回汇一个总结,主对话只看到结果。</p><blockquote><p>一句话先记住:<strong>Subagent = &quot;fork 一个 Claude 干一件事,用完即弃&quot;</strong>。隔离上下文、独立工具集、独立 token 预算。<strong>搜代码、做研究、跑安全审查这种&quot;重读轻写&quot;的事,subagent 最擅长</strong>。</p></blockquote><hr><h2 id="一、为什么需要-subagent" tabindex="-1">一、为什么需要 subagent <a class="header-anchor" href="#一、为什么需要-subagent" aria-label="Permalink to &quot;一、为什么需要 subagent&quot;">​</a></h2><p>主 Claude 一个 session 大概率最后会做这些事:写代码、改文件、改 settings、跑命令。这些动作对<strong>当前的工作上下文</strong>很重要。</p><p>但你也常会让它干一些&quot;探索性&quot;任务:</p><ul><li>&quot;在这个 monorepo 里找所有用了 <code>useReducer</code> 的地方&quot;</li><li>&quot;把 25 个文档读一遍总结今年的销售趋势&quot;</li><li>&quot;用 git log 找 6 个月内改动最频繁的文件 top 10&quot;</li></ul><p>这些事<strong>只是产出一个结论</strong>,过程中读到的几百个文件根本不需要留在主上下文里。如果让主 Claude 自己干,它会:</p><ol><li>Read 一堆文件</li><li>context 膨胀到 100K</li><li>之后干正事时,因为上下文太长开始遗忘</li></ol><p><strong>用 subagent</strong>:</p><ol><li>主 Claude 派任务给 subagent</li><li>Subagent 自己 Read 几百个文件、整理结论</li><li><strong>Subagent 只把&quot;结论&quot;传回主 Claude</strong>(可能就 200 字)</li><li>中间的几百个文件,主 Claude 一行也没看到</li></ol><blockquote><p>这就是 subagent 的根本价值:<strong>用一个独立的 context 窗口完成&quot;探索&quot;,只把&quot;结论&quot;带回来</strong>。主 context 干净,token 省一大截。</p></blockquote><hr><h2 id="二、内置-subagent-explore-plan-general-purpose" tabindex="-1">二、内置 subagent:Explore / Plan / general-purpose <a class="header-anchor" href="#二、内置-subagent-explore-plan-general-purpose" aria-label="Permalink to &quot;二、内置 subagent:Explore / Plan / general-purpose&quot;">​</a></h2><p>Claude Code 默认带几个 subagent:</p><table tabindex="0"><thead><tr><th>subagent</th><th>干什么</th><th>工具</th></tr></thead><tbody><tr><td><strong>Explore</strong></td><td>快速搜索、查代码、找文件</td><td>只读(Read / Glob / Grep / Bash)</td></tr><tr><td><strong>Plan</strong></td><td>软件架构、设计实施方案</td><td>只读</td></tr><tr><td><strong>general-purpose</strong></td><td>通用,什么都能干</td><td>全部工具</td></tr><tr><td><strong>statusline-setup</strong></td><td>配置 status line</td><td>Read / Edit</td></tr></tbody></table><p><strong>主 Claude 调 Task 工具来派 subagent</strong>,基本结构:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Task({</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;subagent_type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Explore&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;找所有 useReducer 用法&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;prompt&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;在 src/ 下找所有用了 useReducer 的文件,列出文件路径和大致用法,不需要展开完整代码&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>返回结果是 subagent 跑完后的最终 message,主 Claude 把它当成 tool 返回结果,继续推理。</p><h3 id="_2-1-explore-的典型用法" tabindex="-1">2.1 Explore 的典型用法 <a class="header-anchor" href="#_2-1-explore-的典型用法" aria-label="Permalink to &quot;2.1 Explore 的典型用法&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task({</span></span>
<span class="line"><span>  description: &quot;定位状态管理代码&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Explore&quot;,</span></span>
<span class="line"><span>  prompt: &quot;在这个 monorepo 里找所有用 zustand 的地方。报告结构:文件路径 | store 名字 | 主要 state 字段 | 调用它的组件数。不超过 200 字。&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p><strong>Explore 是只读的</strong>——它读不写。这意味着:</p><ul><li>不会意外改文件</li><li>适合做&quot;先勘察后决定&quot;的工作</li><li>比 general-purpose 更快(LLM 不用考虑写操作)</li></ul><h3 id="_2-2-plan-的典型用法" tabindex="-1">2.2 Plan 的典型用法 <a class="header-anchor" href="#_2-2-plan-的典型用法" aria-label="Permalink to &quot;2.2 Plan 的典型用法&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task({</span></span>
<span class="line"><span>  description: &quot;设计认证迁移方案&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Plan&quot;,</span></span>
<span class="line"><span>  prompt: &quot;我们要从 session-based auth 迁到 JWT,系统现在有 60 个 API。设计一个 step-by-step 迁移计划:阶段划分 / 风险点 / 兼容期策略 / 回滚方案。&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>Plan 的 prompt 是为&quot;架构思考&quot;调过的——它倾向于产出<strong>可执行的步骤序列</strong>,而不是泛泛而谈。</p><h3 id="_2-3-general-purpose-的典型用法" tabindex="-1">2.3 general-purpose 的典型用法 <a class="header-anchor" href="#_2-3-general-purpose-的典型用法" aria-label="Permalink to &quot;2.3 general-purpose 的典型用法&quot;">​</a></h3><p>任何上面两个不擅长的多步任务:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task({</span></span>
<span class="line"><span>  description: &quot;PR 合规审查&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;general-purpose&quot;,</span></span>
<span class="line"><span>  prompt: &quot;审查 PR #123:跑 \`gh pr diff 123\`,然后跑 \`gh pr view 123\` 看描述,按以下五点逐项审,最后给一句话结论。详细要求:...&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><hr><h2 id="三、自定义-subagent-claude-agents" tabindex="-1">三、自定义 subagent:<code>.claude/agents/</code> <a class="header-anchor" href="#三、自定义-subagent-claude-agents" aria-label="Permalink to &quot;三、自定义 subagent:\`.claude/agents/\`&quot;">​</a></h2><p>内置三种不够用,自己写。</p><p><code>.claude/agents/security-auditor.md</code>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">security-auditor</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">用此 agent 审查安全风险——OWASP Top 10、密钥泄漏、注入、越权。每次涉及 auth / payment / 用户数据的 PR 都该跑。</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob, Bash(gh pr diff:*), Bash(gh pr view:*)</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-opus-4-7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">你是一个专注安全审查的 agent。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">工作流程:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 用 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`gh pr diff\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 看完整 diff</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 按以下顺序检查:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 注入风险(SQL / XSS / Command)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 鉴权 / 授权(IDOR、越权访问)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 密钥泄漏(API key、token、密码硬编码)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 危险依赖(已知 CVE 包)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 输入校验 / 输出转义</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 输出:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 总结一句话(可合并 / 需修复 / 不可合并)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 严重问题列表(按 CVSS 评分排)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 建议修复</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">不要修改文件,只报告。</span></span></code></pre></div><p>frontmatter 字段:</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>name</code></td><td>subagent 名字,主对话用这个调</td></tr><tr><td><code>description</code></td><td>给主 Claude 看的&quot;什么时候用我&quot;的描述,<strong>写好这条决定它会不会被调到</strong></td></tr><tr><td><code>tools</code></td><td>这个 subagent 能用的工具白名单</td></tr><tr><td><code>model</code></td><td>这个 subagent 用什么模型(典型:深度任务 opus,简单的 haiku)</td></tr></tbody></table><p><strong>位置</strong>:</p><ul><li><code>~/.claude/agents/xxx.md</code> —— 用户级</li><li><code>.claude/agents/xxx.md</code> —— 项目级(提交进 git,团队共享)</li></ul><p>调用方式:<code>subagent_type: &quot;security-auditor&quot;</code>。</p><blockquote><p><strong>写自定义 subagent 是 Claude Code 高阶玩家的入门门槛</strong>——你停止只用 Claude Code 提供的能力,开始把自己的&quot;工作流程&quot;封进 agent。</p></blockquote><hr><h2 id="四、subagent-prompt-设计要点" tabindex="-1">四、subagent prompt 设计要点 <a class="header-anchor" href="#四、subagent-prompt-设计要点" aria-label="Permalink to &quot;四、subagent prompt 设计要点&quot;">​</a></h2><p>写 subagent 比写 slash 难——因为 subagent 不知道你和主 Claude 之前聊了什么。每条 prompt 必须<strong>自包含</strong>。</p><h3 id="_4-1-包含必要-context" tabindex="-1">4.1 包含必要 context <a class="header-anchor" href="#_4-1-包含必要-context" aria-label="Permalink to &quot;4.1 包含必要 context&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不好:</span></span>
<span class="line"><span>  Task({prompt: &quot;继续刚才的检查&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>好:</span></span>
<span class="line"><span>  Task({</span></span>
<span class="line"><span>    prompt: &quot;审查 PR #234,这个 PR 改了 auth 模块。</span></span>
<span class="line"><span>    我们用 NextAuth + JWT。重点关注 session 管理、CSRF、token 刷新。</span></span>
<span class="line"><span>    标准:OWASP Top 10。</span></span>
<span class="line"><span>    输出格式:...&quot;</span></span>
<span class="line"><span>  })</span></span></code></pre></div><h3 id="_4-2-写清楚输出格式-长度" tabindex="-1">4.2 写清楚输出格式 / 长度 <a class="header-anchor" href="#_4-2-写清楚输出格式-长度" aria-label="Permalink to &quot;4.2 写清楚输出格式 / 长度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不好:</span></span>
<span class="line"><span>  Task({prompt: &quot;看一下 src/ 都有什么&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>好:</span></span>
<span class="line"><span>  Task({</span></span>
<span class="line"><span>    prompt: &quot;看一下 src/ 都有什么。报告格式:</span></span>
<span class="line"><span>    - 模块清单(每行一个,带一句话说明)</span></span>
<span class="line"><span>    - 入口文件位置</span></span>
<span class="line"><span>    - 主要技术栈关键词</span></span>
<span class="line"><span>    总长度不超过 300 字。&quot;</span></span>
<span class="line"><span>  })</span></span></code></pre></div><blockquote><p>Subagent 的报告要回到主 Claude 的 context,<strong>控制长度比让它&quot;详细&quot;重要 10 倍</strong>。一份 5000 字的报告,主 Claude 看完直接 context 涨 10K,得不偿失。</p></blockquote><h3 id="_4-3-终态可验证" tabindex="-1">4.3 终态可验证 <a class="header-anchor" href="#_4-3-终态可验证" aria-label="Permalink to &quot;4.3 终态可验证&quot;">​</a></h3><p>让 subagent 给&quot;事实&quot;或&quot;列表&quot;,不是&quot;感觉&quot;。<strong>判断 subagent 写得好不好,看它能不能给出可验证的产出</strong>:</p><ul><li>❌ &quot;这个项目代码质量还行&quot;</li><li>✅ &quot;代码质量评估:8/10。问题:src/auth.ts 第 45-67 行有 try-catch 吞错;test 覆盖率 62%(覆盖率工具未跑)&quot;</li></ul><h3 id="_4-4-别让-subagent-做副作用" tabindex="-1">4.4 别让 subagent 做副作用 <a class="header-anchor" href="#_4-4-别让-subagent-做副作用" aria-label="Permalink to &quot;4.4 别让 subagent 做副作用&quot;">​</a></h3><p><strong>Read-only 是 subagent 的最好品类</strong>。让它读、查、分析,<strong>让主 Claude 来执行决策</strong>。</p><p>为什么?subagent 写文件出错了,主 Claude 不知道、你也不知道。读文件出错最多是结论错,不会真的破坏什么。</p><blockquote><p>例外:确实需要长任务自动化时(如批量改 100 个文件),subagent 写也合理——但务必先用 plan mode 让你看一遍计划。</p></blockquote><hr><h2 id="五、何时该用-subagent-何时不该" tabindex="-1">五、何时该用 subagent,何时不该 <a class="header-anchor" href="#五、何时该用-subagent-何时不该" aria-label="Permalink to &quot;五、何时该用 subagent,何时不该&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>用 subagent?</th></tr></thead><tbody><tr><td>&quot;在 monorepo 里找所有 useReducer&quot;</td><td>✅(读多写少)</td></tr><tr><td>&quot;审查这个 PR&quot;</td><td>✅(只读 + 给结论)</td></tr><tr><td>&quot;解释这段代码&quot;(短)</td><td>❌ 主 Claude 直接看就行</td></tr><tr><td>&quot;大改造,改 50 个文件&quot;</td><td>⚠️ 用 Plan subagent 规划,主 Claude 执行</td></tr><tr><td>&quot;调试 bug&quot;</td><td>❌ 主 Claude 来,因为要持续看上下文反应</td></tr><tr><td>&quot;并行做三件无关的探索&quot;</td><td>✅ 三个 subagent 同时发(Task tool 多次并行调用)</td></tr><tr><td>&quot;写一个新 feature&quot;</td><td>❌ 主 Claude 来,subagent 没有项目长期上下文</td></tr></tbody></table><blockquote><p>一条经验:<strong>主 Claude 干&quot;主线&quot;,subagent 干&quot;调研 / 总结 / 审查 / 探索&quot;</strong>。生产代码相关让主 Claude 写,因为写完你要看 diff 再继续推进。</p></blockquote><hr><h2 id="六、并行-subagent" tabindex="-1">六、并行 subagent <a class="header-anchor" href="#六、并行-subagent" aria-label="Permalink to &quot;六、并行 subagent&quot;">​</a></h2><p>主 Claude 一条消息里发<strong>多个 Task 调用</strong>,会真的并行跑:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task({description: &quot;找所有 useState&quot;, ...})</span></span>
<span class="line"><span>Task({description: &quot;找所有 useReducer&quot;, ...})</span></span>
<span class="line"><span>Task({description: &quot;找所有 zustand store&quot;, ...})</span></span></code></pre></div><p>三个 subagent 同时跑,各自独立 context,主 Claude 等三个都回来后汇总。</p><p><strong>这是大规模代码理解最快的姿势</strong>——单线程顺序找 30 分钟的事,并行 5 分钟搞完。</p><blockquote><p>一次开太多并行 subagent token 很贵,一般 2-4 个为宜;<strong>不要一次开 10 个无关的 subagent</strong>,主 Claude 自己会卡在等待。</p></blockquote><hr><h2 id="七、worktree-隔离-让-subagent-在干净环境里跑" tabindex="-1">七、worktree 隔离:让 subagent 在干净环境里跑 <a class="header-anchor" href="#七、worktree-隔离-让-subagent-在干净环境里跑" aria-label="Permalink to &quot;七、worktree 隔离:让 subagent 在干净环境里跑&quot;">​</a></h2><p>写代码的 subagent(尤其是改文件的)有时会希望<strong>在独立的工作树里跑</strong>——不污染主 Claude 当前的修改。</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Task({</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;subagent_type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;general-purpose&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;isolation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;worktree&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;在隔离环境写 feature&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;prompt&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;在 worktree 里实现 dark mode,改完跑测试,把 PR 描述写好&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p><code>isolation: &quot;worktree&quot;</code> 会自动开一个 git worktree,subagent 在那里改;改完如果有改动,worktree 保留路径返回;否则自动清理。</p><p><strong>适合的场景</strong>:实验性改动、不想污染当前分支、并行做几条不冲突的 feature。</p><hr><h2 id="八、subagent-的-transcript-和调试" tabindex="-1">八、subagent 的&quot;transcript&quot;和调试 <a class="header-anchor" href="#八、subagent-的-transcript-和调试" aria-label="Permalink to &quot;八、subagent 的&quot;transcript&quot;和调试&quot;">​</a></h2><p>主 Claude 看到的只是 subagent 的<strong>最终消息</strong>——subagent 自己的中间过程不会进主 context。但你可以单独看:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ctrl+R</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 进 transcript 模式</span></span></code></pre></div><p>里面能展开到 subagent 调用,看它跑了什么 tool、读了什么文件、迭代了几轮。<strong>第一次 subagent 表现不好,大概率 prompt 没写清楚——transcript 能直接看出问题</strong>。</p><hr><h2 id="九、skill-与-subagent-的差别-经常被混" tabindex="-1">九、Skill 与 Subagent 的差别(经常被混) <a class="header-anchor" href="#九、skill-与-subagent-的差别-经常被混" aria-label="Permalink to &quot;九、Skill 与 Subagent 的差别(经常被混)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Subagent</th><th>Skill</th></tr></thead><tbody><tr><td><strong>作用</strong></td><td>派一个独立 Claude 干子任务</td><td>在主 Claude 里&quot;激活&quot;一段专业知识</td></tr><tr><td><strong>上下文</strong></td><td>独立窗口</td><td>共享主 Claude 的上下文</td></tr><tr><td><strong>触发</strong></td><td>主 Claude 主动调 Task</td><td>主 Claude 看到匹配场景自动激活</td></tr><tr><td><strong>配置</strong></td><td><code>.claude/agents/xxx.md</code></td><td><code>~/.claude/skills/xxx/SKILL.md</code></td></tr><tr><td><strong>典型例子</strong></td><td>&quot;做安全审计 → 单独 fork 一个 Claude 跑&quot;</td><td>&quot;做安全审计 → 给主 Claude 加上专业指引&quot;</td></tr></tbody></table><p><strong>怎么选</strong>:</p><ul><li>任务<strong>重读轻写、可隔离上下文</strong> → subagent</li><li>任务<strong>和主流程交织、需要看到全局</strong> → skill</li></ul><p>下一篇会把 skill 讲透。<strong>先把这两个概念差别记住</strong>——很多人 6 个月才搞清楚什么时候用哪个。</p><hr><h2 id="十、踩坑" tabindex="-1">十、踩坑 <a class="header-anchor" href="#十、踩坑" aria-label="Permalink to &quot;十、踩坑&quot;">​</a></h2><ol><li><strong>subagent 当 ChatGPT 用</strong>——<code>Task({prompt: &quot;解释 OAuth&quot;})</code> 这种问题主 Claude 自己回就行,不用开 subagent</li><li><strong>prompt 不写清输出长度</strong>——subagent 写了 5000 字回报,主 context 直接膨胀</li><li><strong>subagent prompt 缺 context</strong>——subagent 不知道你之前的对话,你说&quot;继续刚才那件事&quot;它两眼一抹黑</li><li><strong>让 subagent 写代码,产出不审就 merge</strong>——subagent 写完主 Claude 没看见过程,<strong>真要让它写,先 Plan 子 agent 规划再 general-purpose 执行,且改完一定看 diff</strong></li><li><strong><code>description</code> 写得太宽</strong>——<code>description: &quot;通用 agent&quot;</code> 让 LLM 啥都派给它;<strong>写清楚&quot;什么时候用我&quot;</strong>,LLM 才调得对</li><li><strong><code>tools</code> 给得太宽</strong>——subagent 默认能用所有工具,但应该按需限制;Explore 一类 only-read 的就限定 Read/Glob/Grep</li><li><strong>主 Claude 自己其实更擅长</strong>——尤其是&quot;写一个 feature&quot;这种需要持续看上下文的,<strong>subagent 不擅长这种长链路任务</strong></li><li><strong>不并行</strong>——三件无关的事顺序跑;<strong>一条消息发多个 Task 就并行了</strong>,这件事很多人没意识到</li><li><strong>subagent 改了文件主 Claude 不知道</strong>——主 Claude 后续推理还基于旧文件状态;<strong>subagent 改完,主 Claude 该 Read 一遍再继续</strong></li><li><strong>subagent 一次跑太久</strong>——超过 5 分钟的 subagent 该重新设计,拆成几个小 subagent 串行跑</li></ol><hr><p>下一篇:<code>08-Skills技能系统.md</code>,讲 SKILL.md 的结构、progressive disclosure、和 hook / slash / subagent 的最终对比、&quot;什么时候选 skill&quot;的决策树、写一个有用 skill 的完整例子。</p>`,89)])])}const k=a(i,[["render",l]]);export{g as __pageData,k as default};
